// // This module decodes a 2-bit input 'data' and outputs a 1-bit signal 'q'. The output 'q' is the first bit of the input 'data', not the second bit as intended.
module priority_encoder (
    input [1:0] data,
    input clk,
    output reg q
);

always @(posedge clk) begin
    q <= data[1];
end

endmodule
